package main

import (
	"fmt"
	"mime"
	"net/smtp"
	"strings"
	"time"
)

// BuildFeedbackEmail generates an HTML-formatted email for user feedback
// Parameters:
//   - fromAddr: sender email address
//   - toAddr: recipient email address (support team)
//   - userName: name of the user submitting feedback
//   - subject: feedback subject
//   - feedbackContent: detailed feedback content
// Returns:
//   - emailBody: complete email body with headers and HTML content
//   - err: error if any occurs during email construction
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate inputs
	if fromAddr == "" || toAddr == "" || userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("all parameters are required and cannot be empty")
	}

	// Create email headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = mime.BEncoding.Encode("UTF-8", subject)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=UTF-8"
	headers["Content-Transfer-Encoding"] = "quoted-printable"
	headers["Date"] = time.Now().Format(time.RFC1123Z)

	// Build header string
	var headerBuilder strings.Builder
	for key, value := range headers {
		headerBuilder.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}

	// Build HTML email body
	htmlContent := buildHTMLContent(userName, subject, feedbackContent)

	// Combine headers and body
	emailBody = headerBuilder.String() + "\r\n" + htmlContent

	return emailBody, nil
}

// buildHTMLContent creates the HTML formatted email content
func buildHTMLContent(userName string, subject string, feedbackContent string) string {
	// Escape HTML special characters
	userName = escapeHTML(userName)
	subject = escapeHTML(subject)
	feedbackContent = escapeHTML(feedbackContent)

	htmlTemplate := `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            color: #333;
        }
        .container {
            max-width: 600px;
            margin: 0 auto;
            padding: 20px;
            border: 1px solid #ddd;
            border-radius: 5px;
            background-color: #f9f9f9;
        }
        .header {
            background-color: #4CAF50;
            color: white;
            padding: 15px;
            border-radius: 5px 5px 0 0;
            text-align: center;
        }
        .content {
            padding: 20px;
            background-color: white;
        }
        .field {
            margin-bottom: 15px;
        }
        .label {
            font-weight: bold;
            color: #4CAF50;
            margin-bottom: 5px;
        }
        .value {
            padding: 10px;
            background-color: #f5f5f5;
            border-left: 3px solid #4CAF50;
            padding-left: 10px;
            word-wrap: break-word;
            white-space: pre-wrap;
        }
        .footer {
            text-align: center;
            font-size: 12px;
            color: #666;
            padding: 15px;
            border-top: 1px solid #ddd;
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>User Feedback Submission</h2>
        </div>
        <div class="content">
            <div class="field">
                <div class="label">Username:</div>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <div class="label">Subject:</div>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <div class="label">Feedback Content:</div>
                <div class="value">%s</div>
            </div>
        </div>
        <div class="footer">
            <p>This is an automated message. Please do not reply to this email.</p>
            <p>Submission Time: %s</p>
        </div>
    </div>
</body>
</html>`

	return fmt.Sprintf(htmlTemplate, userName, subject, feedbackContent, time.Now().Format("2006-01-02 15:04:05"))
}

// escapeHTML escapes HTML special characters
func escapeHTML(s string) string {
	replacer := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&#39;",
	)
	return replacer.Replace(s)
}

// SendFeedbackEmail sends the feedback email using SMTP
// This is a helper function to demonstrate how to use the BuildFeedbackEmail function
func SendFeedbackEmail(smtpServer string, smtpPort string, fromAddr string, password string, toAddr string, userName string, subject string, feedbackContent string) error {
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	auth := smtp.PlainAuth("", fromAddr, password, smtpServer)
	err = smtp.SendMail(smtpServer+":"+smtpPort, auth, fromAddr, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

func main() {
	// Example usage of BuildFeedbackEmail
	fromAddr := "user@example.com"
	toAddr := "support@company.com"
	userName := "John Doe"
	subject := "Bug Report: Login Issue"
	feedbackContent := `I encountered an issue while trying to log in to my account.
The login page keeps showing an error message even though I'm using the correct credentials.
This has been happening for the past 2 hours.
Please help me resolve this issue as soon as possible.`

	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("=== Generated Email ===")
	fmt.Println(emailBody)
	fmt.Println("\n=== Email Generated Successfully ===")

	// Example with special characters
	fmt.Println("\n=== Testing with Special Characters ===")
	_, err = BuildFeedbackEmail(
		"test@example.com",
		"support@company.com",
		"Jane <Smith>",
		"Feature Request: Add \"Dark Mode\"",
		"I would like to request a dark mode feature. The current bright theme causes eye strain.",
	)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Email with special characters generated successfully")
	fmt.Println("Subject line:", "Feature Request: Add \"Dark Mode\"")
}

