func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if fromAddr == "" || toAddr == "" || userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("all parameters must be non-empty")
	}

	// Sanitize inputs to prevent email header injection
	fromAddr = strings.TrimSpace(fromAddr)
	toAddr = strings.TrimSpace(toAddr)
	userName = strings.TrimSpace(userName)
	subject = strings.TrimSpace(subject)
	feedbackContent = strings.TrimSpace(feedbackContent)

	// Create email headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = mime.BEncoding.Encode("utf-8", subject)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=utf-8"
	headers["Date"] = time.Now().Format(time.RFC1123Z)

	// Build header string
	var headerBuilder strings.Builder
	for key, value := range headers {
