// SendFeedbackEmail sends the feedback email via SMTP
func SendFeedbackEmail(smtpServer string, smtpPort string, fromAddr string, password string, toAddr string, emailBody string) error {
	auth := smtp.PlainAuth("", fromAddr, password, smtpServer)
	addr := smtpServer + ":" + smtpPort

	// Extract email addresses for SMTP
	fromEmail := strings.TrimSpace(fromAddr)
	toEmail := strings.TrimSpace(toAddr)

	err := smtp.SendMail(addr, auth, fromEmail, []string{toEmail}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

