// escapeHTML escapes HTML special characters
func escapeHTML(s string) string {
	replacer := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&#39;",
	)
	return replacer.Replace(s)
}

// SendFeedbackEmail sends the feedback email using SMTP
// This is a helper function to demonstrate how to use the BuildFeedbackEmail function
func SendFeedbackEmail(smtpServer string, smtpPort string, smtpUser string, smtpPassword string,
	fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {

	// Build the email
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	// Prepare SMTP authentication
	auth := smtp.PlainAuth("", smtpUser, smtpPassword, smtpServer)

	// Send the email
	err = smtp.SendMail(
		smtpServer+":"+smtpPort,
		auth,
		fromAddr,
		[]string{toAddr},
		[]byte(emailBody),
	)

	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

