		toAddr,
		emailSubject,
	)

	// HTML-escape all user inputs to prevent XSS/HTML injection
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct HTML body with escaped content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// sanitizeHeaderValue removes control characters that could be used for header injection
func sanitizeHeaderValue(value string) string {
	// Remove carriage returns, line feeds, and other control characters
	// that could be used to inject additional headers
	value = strings.ReplaceAll(value, "\r", "")
	value = strings.ReplaceAll(value, "\n", "")
	value = strings.ReplaceAll(value, "\t", " ")

	// Remove other potentially dangerous control characters
	var result strings.Builder
	for _, r := range value {
		// Allow printable ASCII and common Unicode characters
		if r >= 32 && r < 127 || r > 127 {
			result.WriteRune(r)
		}
	}

	return result.String()
}

