// BuildFeedbackEmail generates an HTML-formatted email for user feedback
// Parameters:
//   - fromAddr: sender email address
//   - toAddr: recipient email address (support team)
//   - userName: name of the user submitting feedback
//   - subject: feedback subject
//   - feedbackContent: detailed feedback content
// Returns:
//   - emailBody: complete email body with headers and HTML content
//   - err: error if any validation fails
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate inputs
	if fromAddr == "" {
		return "", fmt.Errorf("fromAddr cannot be empty")
	}
	if toAddr == "" {
		return "", fmt.Errorf("toAddr cannot be empty")
	}
	if userName == "" {
		return "", fmt.Errorf("userName cannot be empty")
	}
	if subject == "" {
