// escapeHTML escapes HTML special characters
func escapeHTML(s string) string {
	replacer := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&#39;",
	)
	return replacer.Replace(s)
}

// SendFeedbackEmail sends the feedback email via SMTP
// This is a helper function to demonstrate how to use the BuildFeedbackEmail function
func SendFeedbackEmail(smtpServer string, smtpPort string, auth smtp.Auth, fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return err
	}

	// Send email
	err = smtp.SendMail(
