// BuildFeedbackEmail generates an HTML-formatted email body for user feedback
// Parameters:
//   - fromAddr: sender's email address
//   - toAddr: recipient's email address (support team)
//   - userName: name of the user submitting feedback
//   - subject: feedback subject
//   - feedbackContent: detailed feedback content
// Returns:
//   - emailBody: complete email message with headers and HTML body
//   - err: error if any
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate inputs
	if fromAddr == "" || toAddr == "" || userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("all parameters are required and cannot be empty")
	}

	// Create email headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = mime.QEncoding.Encode("utf-8", subject)
	headers["Date"] = time.Now().Format(time.RFC1123Z)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=\"utf-8\""
	headers["Content-Transfer-Encoding"] = "quoted-printable"

