// BuildFeedbackEmail generates an HTML-formatted email body for user feedback
// Parameters:
//   - fromAddr: sender's email address
//   - toAddr: recipient's email address (support team)
//   - userName: name of the user submitting feedback
//   - subject: feedback subject/title
//   - feedbackContent: detailed feedback content
//
// Returns:
//   - emailBody: complete email body with headers and HTML content
//   - err: error if any occurs during email construction
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate inputs
	if fromAddr == "" || toAddr == "" || userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("all parameters must be non-empty")
	}

	// Create email headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = mime.QEncoding.Encode("utf-8", subject)
	headers["Date"] = time.Now().Format(time.RFC1123Z)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=utf-8"
	headers["Content-Transfer-Encoding"] = "8bit"

	// Build header string
	var headerBuilder strings.Builder
	for key, value := range headers {
		headerBuilder.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}
	headerBuilder.WriteString("\r\n")

	// Build HTML email body
	htmlContent := buildHTMLContent(userName, subject, feedbackContent)

	// Combine headers and body
	emailBody = headerBuilder.String() + htmlContent

	return emailBody, nil
}

// buildHTMLContent constructs the HTML content of the feedback email
func buildHTMLContent(userName string, subject string, feedbackContent string) string {
	htmlTemplate := `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            color: #333;
        }
        .container {
            max-width: 600px;
            margin: 0 auto;
            padding: 20px;
            border: 1px solid #ddd;
            border-radius: 5px;
            background-color: #f9f9f9;
        }
        .header {
            background-color: #007bff;
            color: white;
            padding: 15px;
            border-radius: 5px 5px 0 0;
            text-align: center;
        }
        .content {
            padding: 20px;
            background-color: white;
        }
        .field {
            margin-bottom: 15px;
        }
        .field-label {
            font-weight: bold;
            color: #007bff;
            margin-bottom: 5px;
        }
        .field-value {
            padding: 10px;
            background-color: #f5f5f5;
            border-left: 3px solid #007bff;
            padding-left: 10px;
        }
        .footer {
            margin-top: 20px;
            padding-top: 15px;
            border-top: 1px solid #ddd;
            font-size: 12px;
            color: #666;
            text-align: center;
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>User Feedback Submission</h2>
        </div>
        <div class="content">
            <div class="field">
                <div class="field-label">Username:</div>
                <div class="field-value">%s</div>
            </div>
            <div class="field">
                <div class="field-label">Subject:</div>
                <div class="field-value">%s</div>
            </div>
            <div class="field">
                <div class="field-label">Feedback Content:</div>
                <div class="field-value">%s</div>
            </div>
            <div class="footer">
                <p>This email was automatically generated from the user feedback system.</p>
                <p>Submission Time: %s</p>
            </div>
        </div>
    </div>
</body>
</html>`

	// Escape HTML special characters in user input
	escapedUserName := escapeHTML(userName)
	escapedSubject := escapeHTML(subject)
	escapedContent := escapeHTML(feedbackContent)
	submissionTime := time.Now().Format("2006-01-02 15:04:05 MST")

	return fmt.Sprintf(htmlTemplate, escapedUserName, escapedSubject, escapedContent, submissionTime)
}

// escapeHTML escapes HTML special characters
func escapeHTML(s string) string {
	replacer := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&#39;",
	)
	return replacer.Replace(s)
}

// SendFeedbackEmail sends the feedback email via SMTP
// This is a helper function to demonstrate how to use BuildFeedbackEmail with net/smtp
func SendFeedbackEmail(smtpServer string, smtpPort string, fromAddr string, password string, toAddr string, userName string, subject string, feedbackContent string) error {
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	// Extract email headers and body
	parts := strings.SplitN(emailBody, "\r\n\r\n", 2)
	if len(parts) != 2 {
		return fmt.Errorf("invalid email format")
	}

	// Parse the To address from headers
	auth := smtp.PlainAuth("", fromAddr, password, smtpServer)
	addr := smtpServer + ":" + smtpPort

	err = smtp.SendMail(addr, auth, fromAddr, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

