	subject := "Bug Report: Login Issue"
	feedbackContent := `I encountered an issue when trying to log in to my account.
The system shows an error message "Invalid credentials" even though I'm using the correct password.
This has been happening for the past 2 days.
Please help me resolve this issue.`

	// Generate the email
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
